import re, hashlib
from dataclasses import dataclass

BLOCKLIST = [
    r"ignore (all |previous |above |prior )?instructions",
    r"you are now (DAN|GPT-4|an AI without restrictions)",
    r"repeat (?:the system prompt|your instructions)",
    r"(reveal|show|print) (the |your )?(system prompt|context|instructions)",
    r"\\x[0-9a-f]{2}",          # hex-encoded bypass attempts
    r"<\|im_start\|>",           # ChatML injection
]
COMPILED = [re.compile(p, re.I | re.S) for p in BLOCKLIST]

@dataclass
class InjectionResult:
    blocked: bool
    reason: str | None
    severity: str  # "low" | "medium" | "high"

def screen_prompt(text: str) -> InjectionResult:
    for pat in COMPILED:
        if pat.search(text):
            return InjectionResult(blocked=True, reason=str(pat.pattern), severity="high")
    # Heuristic: unusually long instruction-override pattern
    if len(text) > 8000 and text.count("instruction") > 5:
        return InjectionResult(blocked=True, reason="length+keyword heuristic", severity="medium")
    return InjectionResult(blocked=False, reason=None, severity="low")

def guard(messages: list[dict]) -> None:
    for msg in messages:
        if msg.get("role") in ("user", "tool"):
            result = screen_prompt(str(msg.get("content", "")))
            if result.blocked:
                llm_security_injection.add(1, {"severity": result.severity})
                raise ValueError(f"Prompt injection detected: {result.reason}")

import re

OUTPUT_RULES = [
    # Rule id, pattern, severity
    ("ssn-echo",    re.compile(r"\b\d{3}-\d{2}-\d{4}\b"),       "high"),
    ("cc-echo",     re.compile(r"\b4[0-9]{12,15}\b"),              "high"),
    ("phone-echo",  re.compile(r"\b\+?1?[-.]?\(?\d{3}\)?[-.]?\d{3}[-.]?\d{4}\b"), "medium"),
    ("hate-speech", re.compile(r"\b(slur1|slur2|slur3)\b", re.I), "high"),
]

class OutputBlocked(Exception):
    def __init__(self, rule_id: str, severity: str):
        self.rule_id   = rule_id
        self.severity  = severity
        super().__init__(f"Output blocked by rule {rule_id}")

def filter_output(text: str) -> str:
    for rule_id, pat, severity in OUTPUT_RULES:
        if pat.search(text):
            llm_output_blocked.add(1, {"rule_id": rule_id})
            raise OutputBlocked(rule_id, severity)
    return text

MODEL_TIERS = {
    "gpt-4o-mini":       "standard",
    "claude-haiku-4-5":  "standard",
    "gpt-4o":            "premium",
    "claude-sonnet-4-6": "premium",
    "o1":                "admin",
}
TIER_RANK = {"standard": 1, "premium": 2, "admin": 3}

def check_model_access(model_id: str, caller_tier: str) -> None:
    required = MODEL_TIERS.get(model_id)
    if required is None:
        raise PermissionError(f"Unknown model: {model_id}")
    if TIER_RANK.get(caller_tier, 0) < TIER_RANK[required]:
        raise PermissionError(
            f"Model '{model_id}' requires tier '{required}', caller has '{caller_tier}'"
        )
